import type { Metadata } from "next"
import RentalApplication from "./RentalApplication"

export const metadata: Metadata = {
  title: "入居申込 / 入居審査 | ぐんじょう賃貸管理",
  description:
    "賃貸管理担当・審査担当が入居申込を受け付け、審査を経て決定まで進める画面。申込ヘッダ（申込番号・物件/部屋・賃料・希望入居日・申込日・ステータス）の上で、申込者情報（氏名・年齢・勤務先/業種・年収・勤続年数・雇用形態・現住所・家賃保証会社）を確認し、入居審査基準（年収が必要年収（賃料×12×3＝家賃が月収の1/3以下）以上か・勤続年数・雇用形態・滞納履歴・保証会社の事前承認）を適合/要確認/不適合で判定する。必要書類（本人確認・収入証明・在籍確認・連帯保証人書類・住民票）の受領をチェックリストで管理し、審査ワークフロー（申込受付→書類確認→保証会社審査→オーナー（貸主）承認→審査完了）を段階ごとに担当者・状態・日時とともに進め、差戻しもできる。必須段階と必須書類が揃って初めて、承認/条件付き承認/否認を担当者・日時・理由つきで記録する、入居申込の受付から多段階承認・決定までの審査画面。",
}

export default function RentalApplicationPage() {
  return <RentalApplication />
}

// Seed data for 入居申込 / 入居審査 (rental application + screening) screen.
// All amounts are in JPY (yen). Income figures are 年収 (annual) unless noted.

export type EmploymentType =
  | "正社員"
  | "契約社員"
  | "派遣社員"
  | "パート・アルバイト"
  | "自営業"
  | "公務員"
  | "年金受給"

export interface Applicant {
  name: string
  nameKana: string
  age: number
  employer: string
  industry: string
  /** 年収 in yen. */
  annualIncome: number
  /** 勤続年数 in years. */
  tenureYears: number
  employmentType: EmploymentType
  currentAddress: string
  phone: string
  /** 連帯保証人の有無 / 家賃保証会社. */
  guarantor: string
  guaranteeCompany: string
  /** 過去の家賃滞納履歴. */
  hasDelinquency: boolean
}

export interface Application {
  applicationNo: string
  property: string
  room: string
  layout: string
  /** 月額賃料 (家賃) in yen. */
  rent: number
  /** 管理費・共益費 in yen. */
  managementFee: number
  deposit: number // 敷金 (months stored separately below for display)
  keyMoney: number // 礼金
  desiredMoveInDate: string
  applicationDate: string
  occupants: number
  guaranteeCompanyApproved: boolean // 保証会社の事前審査結果
}

// 入居審査基準 — qualification thresholds.
// 必要年収 = 月額賃料 × 12 × incomeMultiple
// 「家賃は月収の 1/3 以下」⇔ 月収 ≥ 賃料 × 3 ⇔ 年収 ≥ 賃料 × 12 × 3。
// よって incomeMultiple = 3（= 家賃が月収の 1/3）。
export interface QualificationPolicy {
  /** 年収が「月額賃料 × 12 × この倍率」以上であること。3 = 家賃が月収の 1/3。 */
  incomeMultiple: number
  /** 望ましい最低勤続年数。 */
  minTenureYears: number
  /** 要確認となる勤続年数の下限（これ未満は要確認、minTenure以上で適合）。 */
  warnTenureYears: number
}

export const policy: QualificationPolicy = {
  incomeMultiple: 3,
  minTenureYears: 2,
  warnTenureYears: 1,
}

export const applicant: Applicant = {
  name: "佐藤 健太",
  nameKana: "サトウ ケンタ",
  age: 32,
  employer: "株式会社ミライ商事",
  industry: "卸売・小売業",
  annualIncome: 4_800_000,
  tenureYears: 4,
  employmentType: "正社員",
  currentAddress: "東京都江東区東陽 3-12-5 グランハイツ東陽 402",
  phone: "090-1234-5678",
  guarantor: "家賃保証会社利用（連帯保証人なし）",
  guaranteeCompany: "全保連株式会社",
  hasDelinquency: false,
}

export const application: Application = {
  applicationNo: "APP-2026-04821",
  property: "リバーサイド木場 PARK",
  room: "1205号室",
  layout: "1LDK / 42.6㎡",
  rent: 128_000,
  managementFee: 12_000,
  deposit: 256_000, // 2ヶ月
  keyMoney: 128_000, // 1ヶ月
  desiredMoveInDate: "2026年7月15日",
  applicationDate: "2026年6月20日",
  occupants: 1,
  guaranteeCompanyApproved: true,
}

// 必要書類 (document checklist).
export interface RequiredDoc {
  id: string
  label: string
  /** 補足説明. */
  hint: string
  /** 審査必須かどうか（必須書類が未提出だと最終承認できない）。 */
  required: boolean
}

export const requiredDocs: RequiredDoc[] = [
  {
    id: "id",
    label: "本人確認書類",
    hint: "運転免許証 / マイナンバーカード等の写し",
    required: true,
  },
  {
    id: "income",
    label: "収入証明（源泉徴収票）",
    hint: "直近の源泉徴収票 または 課税証明書",
    required: true,
  },
  {
    id: "employment",
    label: "在籍確認",
    hint: "健康保険証 / 在籍証明書",
    required: true,
  },
  {
    id: "guarantor",
    label: "連帯保証人書類",
    hint: "保証会社利用のため任意（保証委託申込書で代替）",
    required: false,
  },
  {
    id: "residence",
    label: "住民票",
    hint: "発行3ヶ月以内・世帯全員記載",
    required: true,
  },
]

// 初期で受領済みの書類ID（在籍確認・住民票はまだ未提出 = 差戻し/書類要求の起点）。
export const initiallyReceivedDocIds = ["id", "income"]

// 審査ワークフロー (screening / approval workflow) stages, in order.
export interface WorkflowStageDef {
  id: string
  label: string
  /** 担当者 / アクター. */
  actor: string
  /** この段階の説明. */
  description: string
}

export const workflowStages: WorkflowStageDef[] = [
  {
    id: "intake",
    label: "申込受付",
    actor: "賃貸管理担当 / 田中",
    description: "入居申込書の受付・初期登録",
  },
  {
    id: "documents",
    label: "書類確認",
    actor: "審査担当 / 山本",
    description: "本人確認・収入証明・在籍・住民票の確認",
  },
  {
    id: "guarantee",
    label: "保証会社審査",
    actor: "全保連株式会社",
    description: "家賃保証会社による与信・保証審査",
  },
  {
    id: "owner",
    label: "オーナー（貸主）承認",
    actor: "貸主 / 木場不動産",
    description: "貸主による入居可否の最終判断",
  },
  {
    id: "complete",
    label: "審査完了",
    actor: "賃貸管理担当 / 田中",
    description: "審査結果の確定・記録",
  },
]

export const REVIEWER = "審査担当 / 山本 美咲"

"use client"

import * as React from "react"
import {
  IconCheck,
  IconAlertTriangle,
  IconX,
  IconBuildingSkyscraper,
  IconUser,
  IconBriefcase,
  IconCoin,
  IconCalendarEvent,
  IconHome,
  IconShieldCheck,
  IconClock,
  IconArrowBackUp,
  IconFileText,
  IconCircleCheck,
  IconCircleDashed,
  IconChevronRight,
} from "@tabler/icons-react"
import {
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Checkbox,
  Statistic,
  MetadataList,
  ReferenceValue,
  ApprovalSteps,
  Alert,
  AlertTitle,
  AlertDescription,
  Separator,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
  DialogClose,
  Textarea,
  FileUploader,
  Icon,
  formatCurrency,
  type ApprovalStep,
  type ApprovalStepState,
} from "@gunjo/ui"

import {
  applicant,
  application,
  policy,
  requiredDocs,
  initiallyReceivedDocIds,
  workflowStages,
  REVIEWER,
} from "./data"

// ── Domain logic ────────────────────────────────────────────────────────────

type CheckStatus = "pass" | "warn" | "fail"

interface QualificationCheck {
  id: string
  label: string
  detail: React.ReactNode
  status: CheckStatus
}

// 必要年収 = 月額賃料 × 12 × 倍率
const requiredAnnualIncome = application.rent * 12 * policy.incomeMultiple

function incomeStatus(): CheckStatus {
  return applicant.annualIncome >= requiredAnnualIncome ? "pass" : "fail"
}

function tenureStatus(): CheckStatus {
  if (applicant.tenureYears >= policy.minTenureYears) return "pass"
  if (applicant.tenureYears >= policy.warnTenureYears) return "warn"
  return "fail"
}

function employmentStatus(): CheckStatus {
  if (applicant.employmentType === "正社員" || applicant.employmentType === "公務員")
    return "pass"
  if (
    applicant.employmentType === "契約社員" ||
    applicant.employmentType === "自営業" ||
    applicant.employmentType === "年金受給"
  )
    return "warn"
  return "warn"
}

const qualificationChecks: QualificationCheck[] = [
  {
    id: "income",
    label: "年収基準",
    detail: (
      <>必要年収 {formatCurrency(requiredAnnualIncome)}（賃料 × 12ヶ月 × {policy.incomeMultiple}）以上</>
    ),
    status: incomeStatus(),
  },
  {
    id: "tenure",
    label: "勤続年数",
    detail: <>現勤務先 {applicant.tenureYears}年（基準 {policy.minTenureYears}年以上）</>,
    status: tenureStatus(),
  },
  {
    id: "employment",
    label: "雇用形態",
    detail: <>{applicant.employmentType}（安定収入の確認）</>,
    status: employmentStatus(),
  },
  {
    id: "delinquency",
    label: "滞納履歴",
    detail: applicant.hasDelinquency ? (
      <>過去に家賃滞納の記録あり</>
    ) : (
      <>過去の滞納履歴なし</>
    ),
    status: applicant.hasDelinquency ? "fail" : "pass",
  },
  {
    id: "guarantee",
    label: "保証会社の事前承認",
    detail: application.guaranteeCompanyApproved ? (
      <>{applicant.guaranteeCompany}：事前承認済み</>
    ) : (
      <>{applicant.guaranteeCompany}：審査中</>
    ),
    status: application.guaranteeCompanyApproved ? "pass" : "warn",
  },
]

const CHECK_VISUAL: Record<
  CheckStatus,
  { label: string; icon: typeof IconCheck; text: string; badge: "success" | "warning" | "destructive" }
> = {
  pass: { label: "適合", icon: IconCheck, text: "text-success-strong", badge: "success" },
  warn: { label: "要確認", icon: IconAlertTriangle, text: "text-warning", badge: "warning" },
  fail: { label: "不適合", icon: IconX, text: "text-destructive", badge: "destructive" },
}

// Decision model ─────────────────────────────────────────────────────────────

type Decision = "approved" | "conditional" | "rejected"

interface DecisionRecord {
  decision: Decision
  reason: string
  by: string
  at: string
}

// Workflow runtime state ─────────────────────────────────────────────────────

type StageStatus = "approved" | "current" | "pending" | "rejected"

interface StageRuntime {
  status: StageStatus
  timestamp?: string
  comment?: string
}

const INITIAL_STAGES: Record<string, StageRuntime> = {
  intake: { status: "approved", timestamp: "2026/06/20 10:32" },
  documents: { status: "current" },
  guarantee: { status: "pending" },
  owner: { status: "pending" },
  complete: { status: "pending" },
}

function nowStamp(): string {
  // Deterministic-friendly: format current time once on the client at action time.
  const d = new Date()
  const pad = (n: number) => String(n).padStart(2, "0")
  return `${d.getFullYear()}/${pad(d.getMonth() + 1)}/${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`
}

const STATE_LABELS: Partial<Record<ApprovalStepState, string>> = {
  approved: "完了",
  current: "進行中",
  pending: "待ち",
  rejected: "差戻し",
}

// ── Component ────────────────────────────────────────────────────────────────

export default function RentalApplication() {
  const [docsReceived, setDocsReceived] = React.useState<Record<string, boolean>>(
    () =>
      Object.fromEntries(
        requiredDocs.map((d) => [d.id, initiallyReceivedDocIds.includes(d.id)])
      )
  )
  const [stages, setStages] = React.useState<Record<string, StageRuntime>>(INITIAL_STAGES)
  const [decision, setDecision] = React.useState<DecisionRecord | null>(null)

  // Dialog state
  const [sendBackOpen, setSendBackOpen] = React.useState(false)
  const [sendBackReason, setSendBackReason] = React.useState("")
  const [decisionOpen, setDecisionOpen] = React.useState(false)
  const [pendingDecision, setPendingDecision] = React.useState<Decision | null>(null)
  const [decisionReason, setDecisionReason] = React.useState("")
  const [requestDocsOpen, setRequestDocsOpen] = React.useState(false)
  const [requestedDocFiles, setRequestedDocFiles] = React.useState<File[]>([])

  // Derived: ordered stage list + index of current stage
  const orderedIds = workflowStages.map((s) => s.id)
  const currentIndex = orderedIds.findIndex((id) => stages[id]?.status === "current")
  const finalStageReached = stages.complete?.status === "approved"

  // Required-stage gate: every non-complete stage must be approved before the
  // final decision is allowed. (complete is recorded BY the decision.)
  const approvalStagesDone = workflowStages
    .filter((s) => s.id !== "complete")
    .every((s) => stages[s.id]?.status === "approved")

  // Document gate: all *required* docs received.
  const requiredDocsReceived = requiredDocs
    .filter((d) => d.required)
    .every((d) => docsReceived[d.id])
  const receivedCount = requiredDocs.filter((d) => docsReceived[d.id]).length

  // Qualification roll-up
  const anyFail = qualificationChecks.some((c) => c.status === "fail")
  const anyWarn = qualificationChecks.some((c) => c.status === "warn")
  const qualSummary: CheckStatus = anyFail ? "fail" : anyWarn ? "warn" : "pass"

  const decisionUnlocked = approvalStagesDone && requiredDocsReceived && !decision

  // ── Actions ────────────────────────────────────────────────────────────────

  function advanceStage() {
    if (currentIndex < 0) return
    const currentId = orderedIds[currentIndex]
    const nextId = orderedIds[currentIndex + 1]
    if (!nextId) return
    setStages((prev) => ({
      ...prev,
      [currentId]: { ...prev[currentId], status: "approved", timestamp: nowStamp() },
      [nextId]: { ...prev[nextId], status: "current" },
    }))
  }

  function submitSendBack() {
    if (currentIndex <= 0) return
    const currentId = orderedIds[currentIndex]
    const prevId = orderedIds[currentIndex - 1]
    const reason = sendBackReason.trim() || "（理由未記入）"
    setStages((prev) => ({
      ...prev,
      [currentId]: { ...prev[currentId], status: "pending", timestamp: undefined, comment: undefined },
      [prevId]: {
        status: "rejected",
        timestamp: nowStamp(),
        comment: `差戻し：${reason}`,
      },
    }))
    setSendBackReason("")
    setSendBackOpen(false)
  }

  function reopenSentBackStage(stageId: string) {
    // After a 差戻し, the actor re-takes the sent-back stage as current.
    setStages((prev) => ({
      ...prev,
      [stageId]: { status: "current", timestamp: undefined, comment: undefined },
    }))
  }

  function openDecision(d: Decision) {
    setPendingDecision(d)
    setDecisionReason("")
    setDecisionOpen(true)
  }

  function confirmDecision() {
    if (!pendingDecision) return
    const labelByDecision: Record<Decision, string> = {
      approved: "承認",
      conditional: "条件付き承認",
      rejected: "否認",
    }
    const reason = decisionReason.trim()
    setDecision({
      decision: pendingDecision,
      reason: reason || (pendingDecision === "approved" ? "基準を満たすため承認" : "—"),
      by: REVIEWER,
      at: nowStamp(),
    })
    // 審査完了 stage is recorded by the decision.
    setStages((prev) => ({
      ...prev,
      complete: {
        status: pendingDecision === "rejected" ? "rejected" : "approved",
        timestamp: nowStamp(),
        comment: `${labelByDecision[pendingDecision]}：${reason || "—"}`,
      },
    }))
    setDecisionOpen(false)
    setPendingDecision(null)
  }

  function resetAll() {
    setDocsReceived(
      Object.fromEntries(
        requiredDocs.map((d) => [d.id, initiallyReceivedDocIds.includes(d.id)])
      )
    )
    setStages(INITIAL_STAGES)
    setDecision(null)
  }

  // ── Build ApprovalSteps props (display layer driven by runtime state) ────────
  const approvalSteps: ApprovalStep[] = workflowStages.map((s) => {
    const rt = stages[s.id]
    const state: ApprovalStepState =
      rt.status === "approved"
        ? "approved"
        : rt.status === "rejected"
        ? "rejected"
        : rt.status === "current"
        ? "current"
        : "pending"
    return {
      label: s.label,
      state,
      actor: s.actor,
      timestamp: rt.timestamp,
      comment: rt.comment,
    }
  })

  // Header status badge
  const headerStatus: { label: string; variant: "info" | "success" | "destructive" | "warning" } =
    decision?.decision === "approved"
      ? { label: "承認", variant: "success" }
      : decision?.decision === "conditional"
      ? { label: "条件付き承認", variant: "warning" }
      : decision?.decision === "rejected"
      ? { label: "否認", variant: "destructive" }
      : { label: "審査中", variant: "info" }

  const currentStageDef = currentIndex >= 0 ? workflowStages[currentIndex] : null
  const sentBackStage = workflowStages.find((s) => stages[s.id]?.status === "rejected" && s.id !== "complete")

  return (
    <main className="mx-auto w-full max-w-6xl px-4 py-6 sm:px-6 sm:py-8">
      {/* ── 申込ヘッダ ───────────────────────────────────────────────────── */}
      <header className="mb-6">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
          <div className="min-w-0">
            <div className="mb-1 flex flex-wrap items-center gap-2">
              <span className="font-mono text-xs text-muted-foreground">
                {application.applicationNo}
              </span>
              <Badge variant={headerStatus.variant}>{headerStatus.label}</Badge>
            </div>
            <h1 className="text-2xl font-bold tracking-tight">入居申込 / 入居審査</h1>
            <p className="mt-1 flex flex-wrap items-center gap-x-2 gap-y-0.5 text-sm text-muted-foreground">
              <Icon icon={IconBuildingSkyscraper} size="sm" />
              <span>{application.property}</span>
              <span aria-hidden>·</span>
              <span>{application.room}</span>
              <span aria-hidden>·</span>
              <span>{application.layout}</span>
            </p>
          </div>
        </div>

        {/* key figures */}
        <div className="mt-4 grid grid-cols-2 gap-3 sm:grid-cols-4">
          <Statistic label="月額賃料" value={formatCurrency(application.rent)} hint={`管理費 ${formatCurrency(application.managementFee)}`} />
          <Statistic
            label="敷金 / 礼金"
            value={`${formatCurrency(application.deposit)}`}
            hint={`礼金 ${formatCurrency(application.keyMoney)}`}
          />
          <Statistic label="希望入居日" value={application.desiredMoveInDate} hint={`入居者 ${application.occupants}名`} />
          <Statistic label="申込日" value={application.applicationDate} hint={`受付 ${application.applicationNo}`} />
        </div>
      </header>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-3">
        {/* ── Left column: applicant + qualification + documents ───────────── */}
        <div className="flex flex-col gap-6 lg:col-span-2">
          {/* 申込者情報 */}
          <Card>
            <CardHeader>
              <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                <Icon icon={IconUser} size="sm" />
                申込者情報
              </CardTitle>
              <CardDescription>
                {applicant.name}（{applicant.nameKana}）· {applicant.age}歳
              </CardDescription>
            </CardHeader>
            <CardContent>
              <MetadataList
                layout="horizontal"
                items={[
                  { label: "氏名", value: applicant.name, description: applicant.nameKana, icon: <Icon icon={IconUser} size="xs" /> },
                  { label: "年齢", value: `${applicant.age}歳` },
                  { label: "勤務先", value: applicant.employer, description: applicant.industry, icon: <Icon icon={IconBriefcase} size="xs" /> },
                  { label: "雇用形態", value: applicant.employmentType },
                  { label: "年収", value: formatCurrency(applicant.annualIncome), icon: <Icon icon={IconCoin} size="xs" /> },
                  { label: "勤続年数", value: `${applicant.tenureYears}年` },
                  { label: "現住所", value: applicant.currentAddress, icon: <Icon icon={IconHome} size="xs" /> },
                  { label: "連絡先", value: applicant.phone },
                  { label: "家賃保証", value: applicant.guaranteeCompany, description: applicant.guarantor, icon: <Icon icon={IconShieldCheck} size="xs" /> },
                ]}
              />
            </CardContent>
          </Card>

          {/* 入居審査基準 */}
          <Card>
            <CardHeader>
              <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                <Icon icon={IconShieldCheck} size="sm" />
                入居審査基準
              </CardTitle>
              <CardDescription>
                年収・勤続・雇用形態・滞納履歴・保証会社の事前承認を基準に判定
              </CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-3">
              {/* 年収基準 — value vs required threshold via ReferenceValue */}
              <div className="rounded-lg border bg-muted/30 p-4">
                <div className="flex flex-wrap items-center justify-between gap-2">
                  <p className="text-sm font-medium">年収基準（必要年収との比較）</p>
                  {(() => {
                    const v = CHECK_VISUAL[incomeStatus()]
                    return (
                      <span className={`inline-flex items-center gap-1 text-sm font-semibold ${v.text}`}>
                        <Icon icon={v.icon} size="xs" aria-hidden /> {v.label}
                      </span>
                    )
                  })()}
                </div>
                <div className="mt-2 flex flex-wrap items-end gap-x-6 gap-y-2">
                  <div>
                    <p className="text-xs text-muted-foreground">申込者の年収</p>
                    <ReferenceValue
                      value={applicant.annualIncome}
                      range={{ low: requiredAnnualIncome }}
                      format={(n) => formatCurrency(n)}
                      showLabel
                      showRange
                      rangeLabel="必要年収"
                      labels={{ normal: "基準を満たす", low: "必要年収に不足" }}
                    />
                  </div>
                </div>
                <p className="mt-2 text-xs text-muted-foreground">
                  必要年収 = 月額賃料 {formatCurrency(application.rent)} × 12ヶ月 × {policy.incomeMultiple}倍 ={" "}
                  <span className="font-medium text-foreground">{formatCurrency(requiredAnnualIncome)}</span>
                  （家賃が月収の約 1/3 以下）
                </p>
              </div>

              {/* other checks */}
              <ul className="flex flex-col divide-y rounded-lg border">
                {qualificationChecks
                  .filter((c) => c.id !== "income")
                  .map((c) => {
                    const v = CHECK_VISUAL[c.status]
                    return (
                      <li key={c.id} className="flex items-start justify-between gap-3 p-3">
                        <div className="min-w-0">
                          <p className="text-sm font-medium">{c.label}</p>
                          <p className="text-xs text-muted-foreground">{c.detail}</p>
                        </div>
                        <Badge variant={v.badge} className="shrink-0 gap-1">
                          <Icon icon={v.icon} size="xs" aria-hidden />
                          {v.label}
                        </Badge>
                      </li>
                    )
                  })}
              </ul>

              <Alert variant={qualSummary === "fail" ? "destructive" : qualSummary === "warn" ? "warning" : "success"}>
                {qualSummary === "fail" ? (
                  <IconX className="h-4 w-4" />
                ) : qualSummary === "warn" ? (
                  <IconAlertTriangle className="h-4 w-4" />
                ) : (
                  <IconCheck className="h-4 w-4" />
                )}
                <AlertTitle as="p">
                  審査サマリ：
                  {qualSummary === "fail" ? "不適合項目あり" : qualSummary === "warn" ? "要確認項目あり" : "全項目適合"}
                </AlertTitle>
                <AlertDescription>
                  {qualSummary === "fail"
                    ? "基準を満たさない項目があります。否認 または 条件付き承認を検討してください。"
                    : qualSummary === "warn"
                    ? "一部に要確認項目があります。条件付き承認（敷金増額・保証人追加 等）も選択肢です。"
                    : "すべての審査基準を満たしています。書類受領と各段階の承認を完了すれば承認可能です。"}
                </AlertDescription>
              </Alert>
            </CardContent>
          </Card>

          {/* 必要書類 */}
          <Card>
            <CardHeader>
              <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                <Icon icon={IconFileText} size="sm" />
                必要書類
              </CardTitle>
              <CardDescription>
                受領 {receivedCount} / {requiredDocs.length} 件
                {requiredDocsReceived ? "（必須書類すべて受領済）" : "（未提出の必須書類があります）"}
              </CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-2">
              <ul className="flex flex-col divide-y rounded-lg border">
                {requiredDocs.map((doc) => {
                  const received = docsReceived[doc.id]
                  return (
                    <li key={doc.id} className="flex items-center justify-between gap-3 p-3">
                      <div className="flex min-w-0 items-start gap-3">
                        <span className="mt-0.5 shrink-0">
                          {received ? (
                            <Icon icon={IconCircleCheck} size="sm" className="text-success-strong" aria-hidden />
                          ) : (
                            <Icon icon={IconCircleDashed} size="sm" className="text-muted-foreground" aria-hidden />
                          )}
                        </span>
                        <div className="min-w-0">
                          <p className="flex flex-wrap items-center gap-1.5 text-sm font-medium">
                            {doc.label}
                            {doc.required ? (
                              <span className="text-[10px] font-semibold text-destructive">必須</span>
                            ) : (
                              <span className="text-[10px] font-medium text-muted-foreground">任意</span>
                            )}
                          </p>
                          <p className="text-xs text-muted-foreground">{doc.hint}</p>
                          <span className={`mt-0.5 inline-flex items-center gap-1 text-xs font-medium ${received ? "text-success-strong" : "text-muted-foreground"}`}>
                            <Icon icon={received ? IconCircleCheck : IconCircleDashed} size="xs" aria-hidden />
                            {received ? "受領済" : "未提出"}
                          </span>
                        </div>
                      </div>
                      <Checkbox
                        checked={received}
                        onCheckedChange={(c) =>
                          setDocsReceived((prev) => ({ ...prev, [doc.id]: c }))
                        }
                        aria-label={`${doc.label}を受領済にする`}
                      />
                    </li>
                  )
                })}
              </ul>
              <div>
                <Button variant="outline" size="sm" onClick={() => setRequestDocsOpen(true)}>
                  <IconFileText className="mr-1.5 h-4 w-4" />
                  書類を要求 / アップロード
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* ── Right column: workflow + decision + actions ──────────────────── */}
        <div className="flex flex-col gap-6">
          {/* 審査ワークフロー */}
          <Card>
            <CardHeader>
              <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                <Icon icon={IconClock} size="sm" />
                審査ワークフロー
              </CardTitle>
              <CardDescription>
                {finalStageReached
                  ? "審査は完了しています。"
                  : currentStageDef
                  ? `現在の段階：${currentStageDef.label}`
                  : "次の段階を確認してください。"}
              </CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-4">
              {/* current-stage is programmatically discoverable */}
              <div aria-live="polite">
                <ApprovalSteps steps={approvalSteps} stateLabels={STATE_LABELS} />
              </div>

              {/* hidden semantic note for the current stage */}
              {currentStageDef ? (
                <p className="sr-only" aria-current="step">
                  現在の審査段階は {currentStageDef.label}（担当：{currentStageDef.actor}）です。
                </p>
              ) : null}

              {!decision ? (
                <div className="flex flex-col gap-2">
                  {sentBackStage ? (
                    <Alert variant="warning">
                      <IconArrowBackUp className="h-4 w-4" />
                      <AlertTitle as="p">差戻し中：{sentBackStage.label}</AlertTitle>
                      <AlertDescription>
                        {stages[sentBackStage.id]?.comment}
                        <div className="mt-2">
                          <Button size="sm" variant="outline" onClick={() => reopenSentBackStage(sentBackStage.id)}>
                            {sentBackStage.label} を再開
                          </Button>
                        </div>
                      </AlertDescription>
                    </Alert>
                  ) : null}

                  <div className="flex flex-wrap gap-2">
                    <Button
                      onClick={advanceStage}
                      disabled={!currentStageDef || currentStageDef.id === "complete"}
                    >
                      <IconChevronRight className="mr-1 h-4 w-4" />
                      審査を進める
                    </Button>
                    <Button
                      variant="outline"
                      onClick={() => setSendBackOpen(true)}
                      disabled={currentIndex <= 0}
                    >
                      <IconArrowBackUp className="mr-1 h-4 w-4" />
                      差戻し
                    </Button>
                  </div>
                </div>
              ) : null}
            </CardContent>
          </Card>

          {/* 審査結果 / decision */}
          <Card>
            <CardHeader>
              <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                <Icon icon={IconCircleCheck} size="sm" />
                審査結果
              </CardTitle>
              <CardDescription>承認 / 条件付き承認 / 否認 を記録します</CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-3">
              {decision ? (
                <Alert
                  variant={
                    decision.decision === "approved"
                      ? "success"
                      : decision.decision === "conditional"
                      ? "warning"
                      : "destructive"
                  }
                >
                  {decision.decision === "rejected" ? (
                    <IconX className="h-4 w-4" />
                  ) : decision.decision === "conditional" ? (
                    <IconAlertTriangle className="h-4 w-4" />
                  ) : (
                    <IconCheck className="h-4 w-4" />
                  )}
                  <AlertTitle as="p">
                    {decision.decision === "approved"
                      ? "承認"
                      : decision.decision === "conditional"
                      ? "条件付き承認"
                      : "否認"}
                  </AlertTitle>
                  <AlertDescription>
                    <p className="font-medium text-foreground">{decision.reason}</p>
                    <p className="mt-1 text-muted-foreground">
                      {decision.by} · {decision.at}
                    </p>
                  </AlertDescription>
                </Alert>
              ) : (
                <>
                  {!decisionUnlocked ? (
                    <Alert variant="info">
                      <IconClock className="h-4 w-4" />
                      <AlertTitle as="p">最終判断はまだ確定できません</AlertTitle>
                      <AlertDescription>
                        <ul className="ml-4 list-disc space-y-0.5">
                          {!approvalStagesDone ? (
                            <li>各審査段階（保証会社・オーナー承認まで）を完了してください。</li>
                          ) : null}
                          {!requiredDocsReceived ? <li>必須書類をすべて受領してください。</li> : null}
                        </ul>
                      </AlertDescription>
                    </Alert>
                  ) : (
                    <Alert variant="success">
                      <IconCheck className="h-4 w-4" />
                      <AlertTitle as="p">最終判断が可能です</AlertTitle>
                      <AlertDescription>すべての段階と必須書類が揃いました。</AlertDescription>
                    </Alert>
                  )}

                  <Separator />

                  <div className="flex flex-col gap-2">
                    <Button onClick={() => openDecision("approved")} disabled={!decisionUnlocked}>
                      <IconCheck className="mr-1 h-4 w-4" />
                      承認する
                    </Button>
                    <Button
                      variant="outline"
                      onClick={() => openDecision("conditional")}
                      disabled={!decisionUnlocked}
                    >
                      <IconAlertTriangle className="mr-1 h-4 w-4" />
                      条件付き承認
                    </Button>
                    <Button
                      variant="destructive"
                      onClick={() => openDecision("rejected")}
                      disabled={!!decision}
                    >
                      <IconX className="mr-1 h-4 w-4" />
                      否認する
                    </Button>
                  </div>
                </>
              )}

              {decision ? (
                <div>
                  <Button variant="ghost" size="sm" onClick={resetAll}>
                    審査をやり直す（デモ）
                  </Button>
                </div>
              ) : null}
            </CardContent>
          </Card>
        </div>
      </div>

      {/* ── 差戻し Dialog ────────────────────────────────────────────────── */}
      <Dialog open={sendBackOpen} onOpenChange={setSendBackOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>差戻し（前の段階へ戻す）</DialogTitle>
            <DialogDescription>
              {currentStageDef ? `「${currentStageDef.label}」を前の担当者へ差し戻します。` : ""}
              理由を記入してください。
            </DialogDescription>
          </DialogHeader>
          <Textarea
            label="差戻し理由"
            description="差戻し先の担当者に表示されます。"
            value={sendBackReason}
            onChange={(e) => setSendBackReason(e.target.value)}
            placeholder="例：在籍確認の書類が未提出のため、追加提出を依頼"
          />
          <DialogFooter>
            <DialogClose asChild>
              <Button variant="outline">キャンセル</Button>
            </DialogClose>
            <Button variant="destructive" onClick={submitSendBack}>
              差戻しを記録
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* ── Decision Dialog ──────────────────────────────────────────────── */}
      <Dialog open={decisionOpen} onOpenChange={setDecisionOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>
              {pendingDecision === "approved"
                ? "承認の確定"
                : pendingDecision === "conditional"
                ? "条件付き承認の確定"
                : "否認の確定"}
            </DialogTitle>
            <DialogDescription>
              {pendingDecision === "conditional"
                ? "条件（敷金増額・保証人追加 等）を記入してください。"
                : pendingDecision === "rejected"
                ? "否認の理由を記入してください（申込者へ通知されます）。"
                : "承認のコメント（任意）を記入できます。"}
            </DialogDescription>
          </DialogHeader>
          <Textarea
            label={
              pendingDecision === "conditional"
                ? "付帯条件"
                : pendingDecision === "rejected"
                ? "否認理由"
                : "コメント（任意）"
            }
            value={decisionReason}
            onChange={(e) => setDecisionReason(e.target.value)}
            placeholder={
              pendingDecision === "conditional"
                ? "例：敷金を1ヶ月増額（計3ヶ月）の上で承認"
                : pendingDecision === "rejected"
                ? "例：必要年収に満たないため"
                : "例：審査基準をすべて満たすため承認"
            }
          />
          <DialogFooter>
            <DialogClose asChild>
              <Button variant="outline">キャンセル</Button>
            </DialogClose>
            <Button
              variant={pendingDecision === "rejected" ? "destructive" : "default"}
              onClick={confirmDecision}
              disabled={
                (pendingDecision === "rejected" || pendingDecision === "conditional") &&
                !decisionReason.trim()
              }
            >
              記録する
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* ── 書類要求 / Upload Dialog ─────────────────────────────────────── */}
      <Dialog open={requestDocsOpen} onOpenChange={setRequestDocsOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>書類の要求 / アップロード</DialogTitle>
            <DialogDescription>
              不足している書類をアップロード、または申込者へ提出を依頼します。
            </DialogDescription>
          </DialogHeader>
          <FileUploader
            value={requestedDocFiles}
            onValueChange={setRequestedDocFiles}
            maxFiles={5}
            accept={{ "application/pdf": [".pdf"], "image/*": [".png", ".jpg", ".jpeg"] }}
            labels={{
              browse: "クリックしてアップロード",
              drop: "またはドラッグ＆ドロップ",
              maxSize: (mb) => `最大 ${mb}MB（PDF / 画像）`,
              removeFile: "削除",
            }}
          />
          <DialogFooter>
            <DialogClose asChild>
              <Button variant="outline">閉じる</Button>
            </DialogClose>
            <Button onClick={() => setRequestDocsOpen(false)}>
              申込者へ提出を依頼
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </main>
  )
}
